window.__QUIZ_DATA__=[{"id":"objective>Biology>2020>1","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The cell as the basic unit of life consists of","images":[],"options":{"A":"Cell wall and vacuole","B":"Nucleus and cell wall","C":"cytoplasm and nucleus","D":"Cytoplasm and vacuole"},"answer":"C","explanation":"The cell, being the basic unit of life, consists of the cytoplasm and the nucleus. The cytoplasm is the jelly-like substance that contains all the cell's organelles, excluding the nucleus. The nucleus, on the other hand, is the control center of the cell, containing the cell's DNA and regulating the cell's activities.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>2","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Use the following Classes of Arthropoda to answer the question below  I. Crustaceans  II. Insecta  III. Arachnida  IV.Chilopoda    Which members of the classes live mainly in an aquatic habitat","images":[],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"Crustaceans are the members of the classes that live mainly in an aquatic habitat. Crustaceans include animals like crabs, lobsters, crayfish, shrimps, krill, woodlice, and barnacles. Most of these animals are aquatic, living in either freshwater or marine environments, and some are terrestrial.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>3","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Use the following Classes of Arthropoda to answer the question below  I. Crustaceans  II. Insecta  III. Arachnida  IV.Chilopoda  Which of the classes is charaterised by the possession of two pairs of antennae?","images":[],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"Crustaceans are the only arthropods that have two pairs of antennae. The pairs attached to the first segment of the head are called primary antennae or antennules. The pair attacked secondary antennae or simply antenna","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>4","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The organisms with spiral chloroplast and nucleus suspended by cytoplasmic strands is","images":[],"options":{"A":"Volvox","B":"Spirogyra","C":"Paramecius","D":"Euglena"},"answer":"B","explanation":"Spirogyra is a genus of filamentous green algae characterized by its spiral chloroplasts and a nucleus that is suspended by cytoplasmic strands. Volvox is a colonial green algae, Paramecium is a ciliate protozoan, and Euglena is a genus of single-celled flagellate eukaryotes, none of which have the described characteristics.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>5","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The Network of double membrane that conveys materials through the cytoplasm is the","images":[],"options":{"A":"Plasma membrane","B":"nuclear Membrane","C":"Mitochondrion","D":"Endoplasmic reticulum"},"answer":"D","explanation":"The network of double membrane that conveys materials through the cytoplasm is the Endoplasmic Reticulum. The Endoplasmic Reticulum (ER) is an organelle in cells that serves as a manufacturing and packaging system. It works closely with the Golgi apparatus, ribosomes, mRNA, and tRNA. Structurally, the endoplasmic reticulum is a network of membranes found throughout the cell and connected to the nucleus.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>6","subject":"Biology","year":"2020","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The diagram above is an illustration of the longitudinal section of a plant organ. Study to answer the question below      Food is stored in the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"B","explanation":"Food is stored in the part labelled II. The part labelled II is the fleshy leaf. The fleshy leaves are modified leaves that store nutrients, primarily in the form of carbohydrates.  Structure: The fleshy leaves of an onion bulb are thick, succulent, and often layered. They form concentric circles around a central point, with the outer layers being more papery and the inner layers being thicker and juicier.  Function: The primary function of these fleshy leaves is to store food, mainly carbohydrates like fructans and glucose, which provide energy for the plant to grow new shoots and roots. This storage helps the plant survive periods when it cannot photosynthesize, such as during dormancy.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>7","subject":"Biology","year":"2020","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The diagram above is an illustration of the longitudinal section of a plant organ. Study to answer the question below    The plant is a","images":["data:image/png;base64,"],"options":{"A":"stem tuber","B":"Bulb","C":"stolon","D":"runner"},"answer":"B","explanation":"The plant is a bulb. The onion bulb is a modified stem","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>8","subject":"Biology","year":"2020","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The diagram above is an illustration of the longitudinal section of a plant organ. Study to answer the question below    The part labelled I is the","images":["data:image/png;base64,"],"options":{"A":"Apical bud","B":"Scale leaf","C":"Adventious root","D":"Fleshy leaf"},"answer":"B","explanation":"The part labelled I is the scale leaf. In an onion bulb, scale leaves are thick, fleshy layers arranged in concentric circles. They store nutrients, mainly carbohydrates, for the plant's survival and regrowth. The outermost scales are dry and papery, providing protection against damage and dehydration.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>9","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"Which of the following is not a living semi permeable membrane?","images":[],"options":{"A":"Pig's bladder","B":"Unripe pawpaw fruit","C":"Yam tuber","D":"sheet of cellophane"},"answer":"D","explanation":"A sheet of cellophane is not a living semi-permeable membrane. Semi-permeable membranes are thin layers of material capable of separating substances when a driving force is applied across the membrane. It allows certain molecules or ions to pass through it by diffusion and occasionally specialized 'facilitated diffusion'. The other options listed are all examples of living semi-permeable membranes.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>10","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.","question":"In an experiment, mould and yeast cells were transferred into an environment with low oxygen concerntration . After few days, the mould died while the yeast cells did not. which of the following staement best explains the above observation","images":[],"options":{"A":"The yeast cells carried out photosynthesis while the mould did not","B":"Photosynthesis does not take place in the absence of oxygen","C":"Respiration can take place in yeast cells in the absence of oxygen","D":"Respiration does not occur in the Mould"},"answer":"C","explanation":"The yeast cells can survive in an environment with low oxygen concentration because they can carry out anaerobic respiration, also known as fermentation. This process does not require oxygen. On the other hand, moulds are aerobic organisms that require oxygen for respiration, hence they cannot survive in an environment with low oxygen concentration.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>11","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Which of the following does not provide support in flowering plants?","images":[],"options":{"A":"Collenchyma","B":"Parenchyma","C":"Xylem","D":"Phloem"},"answer":"D","explanation":"The supporting tissue in plants include  - The collenchyma  - The sclerenchyma  -Xylem Also responsible for the transport dispersal of water and nutrient.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>12","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"The diagram is an illustration of an experimental set-up. Study it and answer the question:      The set-up directly measures","images":["data:image/png;base64,"],"options":{"A":"Transpiration of water by shoot","B":"Evaporation of water from leaves","C":"Absorption of water by the shoot","D":"Loss of mineral salts from the leaves"},"answer":"A","explanation":"The set-up measure comparatively the rate of transpiration of a single shoot of a plant under experimental condition.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>13","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"The diagram is an illustration of an experimental set-up. Study it and answer the question:    The set-up can measure comparatively the rate of","images":["data:image/png;base64,"],"options":{"A":"Evapouration from leaves on a single shoot under different experimental conditions.","B":"Salt uptake by shoots from different plants","C":"transpiration of single shoot of plant under different experimental conditions","D":"Water uptake by roots of different plants."},"answer":"C","explanation":"The set-up measure comparatively the rate of transpiration of a single shoot of a plant under experimental conditions.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>14","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"The respiration organ of a cockroach is the","images":[],"options":{"A":"air sac","B":"trachea","C":"lung book","D":"lung"},"answer":"B","explanation":"The respiratory organ of a cockroach is the trachea. Insects like cockroaches do not have lungs. Instead, they breathe through a network of tiny tubes called tracheae. Oxygen from the air enters the tracheae through a row of holes along an insect's abdomen. The oxygen then diffuses down the blind-ended tracheae. So, the correct answer is trachea.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>15","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"The excretory product of some reptiles, bird and insect is","images":[],"options":{"A":"urea","B":"urine","C":"ammonia","D":"uric acid"},"answer":"D","explanation":"The excretory product of some reptiles, birds, and insects is uric acid. These organisms are known as uricotelic organisms. Uric acid is a compound that is excreted by these organisms instead of urea or ammonia. Uric acid is less toxic than ammonia and urea, and it is also less soluble in water. This means that it can be excreted with minimal water loss, which is beneficial for organisms that live in dry environments. So, the correct answer is uric acid.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>16","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"The part of the mammalian kidney that stores urine is the","images":["data:image/png;base64,"],"options":{"A":"capsule","B":"medulla","C":"pelvic","D":"bladder"},"answer":"D","explanation":"The bladder is the part of kidney that stores urine. it stores urine before it is transferred to the ureter","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>17","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"The properties of endocrines system includes the following except","images":[],"options":{"A":"secretion of hormones","B":"transportation by blood to target organs","C":"having specific effect","D":"release of secretion into ducts"},"answer":"D","explanation":"The endocrine system is a collection of glands that produce hormones that regulate metabolism, growth and development, tissue function, sexual function, reproduction, sleep, and mood, among other things. Unlike exocrine glands (such as sweat glands), endocrine glands do not release their secretions into ducts. Instead, they release hormones directly into the bloodstream, which transports the hormones to cells throughout the body.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>18","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"The part of the central nervous system that controls unconscious actions in human is the","images":[],"options":{"A":"cerebellum","B":"cerebrum","C":"spinal cord","D":"optic nerve"},"answer":"C","explanation":"The spinal cord is responsible for controlling many unconscious actions in humans, such as:    - Reflexes (e.g., withdrawing a hand from a hot surface)  - Autonomic functions (e.g., heart rate, blood pressure, digestion)  - Motor functions (e.g., walking, balance, coordination)    The other options are not primarily responsible for controlling unconscious actions:    - Cerebellum: coordinates voluntary movements, balance, and posture  - Cerebrum: processes sensory information, controls voluntary actions, and manages higher-level cognitive functions  - Optic nerves: transmit visual information from the eyes to the brain","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>19","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"What happens when the ciliary muscles of the eye contracts? The","images":[],"options":{"A":"lens becomes more concave","B":"lens becomes more convex","C":"lens gets a longer focal lenght","D":"suspensory ligament becomes tight"},"answer":"B","explanation":"When the ciliary muscles of the eye contract, the lens becomes more convex. This is because the contraction of the ciliary muscles reduces the tension on the suspensory ligaments holding the lens in place, allowing the lens to take on a more rounded (convex) shape. This increases the lens's refractive power, allowing for closer objects to be brought into focus.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>20","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The function of the part labelled I is","images":["data:image/png;base64,"],"options":{"A":"receiving the pollen grain","B":"passage for the male gamate to the ovary","C":"germination of the pollen grain","D":"site for double fertilization in the plant"},"answer":"B","explanation":"The part labelled I is the pollen tube and it transfers pollen grain from anther to the ovary","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>21","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"The part labelled II is the","images":["data:image/png;base64,"],"options":{"A":"unfused stigma","B":"fused style","C":"fused ovaries","D":"unfused anther"},"answer":"C","explanation":"The part labelled II in the diagram is the fused ovaries.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>22","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.","question":"The reagent used in testing for carbon(IV) oxide is","images":[],"options":{"A":"copper sulphate solution","B":"lime water","C":"hydrochloric acid","D":"sodium hydroxide solution"},"answer":"B","explanation":"The reagent used in testing for carbon(IV) oxide, also known as carbon dioxide, is lime water. When carbon dioxide is bubbled through lime water, it reacts with the lime water to form calcium carbonate, which is a white precipitate. This reaction is used as a test for the presence of carbon dioxide.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>23","subject":"Biology","year":"2020","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Oxygen comes out of the stomata during photosynthesis through the process known as","images":[],"options":{"A":"Diffusion","B":"transpiration pull","C":"osmosis","D":"active transport"},"answer":"A","explanation":"During photosynthesis, oxygen is produced as a by-product in the chloroplasts of the plant cells. This oxygen then diffuses out of the plant through the stomata. Diffusion is a passive process where molecules move from an area of high concentration to an area of low concentration. In this case, the oxygen molecules move from inside the plant where their concentration is high, to the outside where the concentration is lower.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>24","subject":"Biology","year":"2020","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The first stable product of photosynthesis is","images":[],"options":{"A":"Starch","B":"Fructose","C":"Glucose","D":"Sucrose"},"answer":"C","explanation":"The first stable product of photosynthesis is glucose. Photosynthesis is a process used by plants and other organisms to convert light energy into chemical energy that can later be released to fuel the organisms' activities. This chemical energy is stored in carbohydrate molecules, such as sugars, which are synthesized from carbon dioxide and water. The first stable product of this process is glucose.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>25","subject":"Biology","year":"2020","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"An example of trace element is","images":[],"options":{"A":"potassium","B":"Calcuim","C":"Magnesium","D":"Copper"},"answer":"D","explanation":"Trace elements are elements required by an organism in only minute quantities. Copper is a trace element because it is needed in very small amounts. It is used by the body to help make red blood cells and keep nerve cells and the immune system healthy. Other options like potassium, calcium, and magnesium are macro-elements, not trace elements, because they are needed by the body in larger amounts.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>26","subject":"Biology","year":"2020","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Which of the following statement about a mixture of a protein-digesting enzyme and starch solution would be correct ? The protein-digesting enzyme.","images":[],"options":{"A":"has no effect on the starch solution","B":"Leads to production of amino acids","C":"leads to the production of glucose","D":"Digest the starch"},"answer":"A","explanation":"A protein-digesting enzyme, such as pepsin or trypsin, would have no effect on a starch solution because these enzymes are specific to proteins and do not act on starch. Enzymes are biological catalysts that speed up chemical reactions in living organisms, and they are highly specific, meaning each enzyme only catalyzes a specific reaction. In this case, the protein-digesting enzyme would not lead to the production of amino acids, glucose, or digest the starch because it does not act on starch.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>27","subject":"Biology","year":"2020","type":"Objective","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"A mutualism type of relationship is different from a parasitic relationship because in mutualism","images":[],"options":{"A":"Both organisms involved benefit","B":"none of the organism benefits or harm each other","C":"Both organism harm each other","D":"Only one of the organism is harmed"},"answer":"A","explanation":"In a mutualistic relationship, both organisms involved benefit from the relationship. This is different from a parasitic relationship where only one organism (the parasite) benefits at the expense of the other (the host).","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>28","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"The table shows the number of some organism in habitats W and Y.   Organismnumber in the habitatnumber in the habitathabitat W habitat YPlankton1260Antelope051Water flea100Tilapia230Lion 06Frog60Grass0250    What type of habitat is W?","images":[],"options":{"A":"Rainforest","B":"Pond","C":"Desert","D":"Ocean"},"answer":"B","explanation":"Habitat W is likely a pond. This is inferred from the presence of organisms such as plankton, water fleas, tilapia, and frogs, which are typically found in freshwater environments like ponds. Rainforests, deserts, and oceans would not typically have this combination of organisms.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2020>29","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"The table shows the number of some organism in habitats W and Y.   Organismnumber in the habitatnumber in the habitathabitat W habitat YPlankton1260Antelope051Water flea100Tilapia230Lion 06Frog60Grass0250  Which of the following statement about habitat W is correct ? The","images":[],"options":{"A":"Absence of lions and antelope shows that the habitat is terrestial","B":"Presence of Tilapia and Planktons shows that the habitat is not aquatic","C":"Type of organism present indicate that the habitat is aquatic","D":"Absence of grass indicates that the habitat is terrestial"},"answer":"C","explanation":"The presence of organisms such as Plankton, Water flea, Tilapia, and Frog in habitat W indicates that the habitat is aquatic. Plankton and Water flea are small organisms that live in water bodies. Tilapia is a type of fish, and frogs are amphibians that live both on land and in water but breed in water. Therefore, the type of organisms present indicates that the habitat is aquatic.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2020>30","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"The table shows the number of some organism in habitats W and Y.   Organismnumber in the habitatnumber in the habitathabitat W habitat YPlankton1260Antelope051Water flea100Tilapia230Lion 06Frog60Grass0250  The number of lions and antelopes in habitat Y shows that lion","images":[],"options":{"A":"Is the prey while the antelope is the predator","B":"is the predator while the antelope is the prey","C":"and the antelope are prey to each other","D":"and the antelopes are predators"},"answer":"B","explanation":"In a typical ecological habitat the prey is usually more than the predator. In the table presented in the question , there are 6 lions and 51 antelopes in the habitat (terrestial)","marks":"1","difficulty":"3"},{"id":"objective>Biology>2020>31","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS","question":"The diagram below is an illustration of an ecological instrusment.      A disadvantage of the abiotic factor measured by the instrument is that it.","images":["data:image/png;base64,"],"options":{"A":"is an agent of pollination","B":"is necessary for gemination","C":"leads to flooding when is excess","D":"is used for irrigation."},"answer":"C","explanation":"The diagram in the question is a rain gauge. Rain gauge is used to measure rainfall. When rainfall is an excess it could lead to flooding","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>32","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS","question":"The diagram below is an illustration of an ecological instrusment.    When the instrument is in use, it is usually","images":["data:image/png;base64,"],"options":{"A":"Placed slightly above soil level","B":"placed on a table","C":"suspended in air","D":"suspended on moving water"},"answer":"A","explanation":"When raingauge is in use, it is usually placed above the soil level in an open space. Where there are no obstacles to prevent rainfall.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>33","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Soil with the finest texture is","images":[],"options":{"A":"Silt","B":"clay","C":"sand","D":"Gravel"},"answer":"B","explanation":"Clay soil has the finest texture. The texture of the soil is determined by the size of the particles that make up the soil. The smallest particles are found in clay soil, making it have the finest texture. Silt, sand, and gravel have larger particles and therefore do not have as fine a texture as clay.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>34","subject":"Biology","year":"2020","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"The position occupied by organism in a food chain is the","images":[],"options":{"A":"energy level","B":"niche","C":"Trophic level","D":"Biomass"},"answer":"C","explanation":"The position occupied by an organism in a food chain is the trophic level. A food chain represents the flow of energy from one organism to another. The trophic level of an organism is its position in a food chain or food web, which is determined by its feeding relationships. The energy level and biomass are related to the trophic level, but they are not the position an organism occupies in a food chain. The niche of an organism is its role in the ecosystem, not its position in the food chain.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>35","subject":"Biology","year":"2020","type":"Objective","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"The depletion of ozone layer will result in the earth surface receiving more","images":[],"options":{"A":"gamma ray","B":"infra-red rays","C":"Ultraviolet rays","D":"X-rays"},"answer":"C","explanation":"The ozone layer in the earth's stratosphere absorbs most of the Sun's ultraviolet (UV) radiation. It contains high concentrations of ozone (O3) in relation to other parts of the atmosphere. If the ozone layer depletes, more UV rays will reach the earth's surface.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>36","subject":"Biology","year":"2020","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Using the list of insects below to answer the question below:  I - cotton stainer   II - honeybee  III - Termite   IV - Weevil    The insects whose activities are both beneficial and harmful to human are","images":[],"options":{"A":"I and II","B":"II and III","C":"II and IV","D":"III and IV"},"answer":"B","explanation":"Honeybees are beneficial to humans as they help in pollination of flowers, and also produce honey which is used by humans. However, they can also be harmful as their stings can cause allergic reactions. Termites are harmful as they destroy wooden structures, but they are also beneficial as they play a crucial role in nutrient cycling, soil formation and the flow of water and energy through ecosystems.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>37","subject":"Biology","year":"2020","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Using the list of insects below to answer the question below:  I - cotton stainer   II - honeybee  III - Termite   IV - Weevil  Which of the insect destroys grains","images":[],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"D","explanation":"Weevils are known to be pests of stored grains. They lay their eggs in the grain kernels and the larvae feed on the grain from the inside, causing destruction.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>38","subject":"Biology","year":"2020","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Conversation of natural resources does not","images":[],"options":{"A":"Maintain a balance ecosystem","B":"Preserve the beauty of nature","C":"attract tourist","D":"Threaten the survival of species"},"answer":"D","explanation":"Coversion of natural resources does not threaten the survival of species . converstion of natural resources involves the judious use of natural resources .","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>39","subject":"Biology","year":"2020","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : WILDLIFE, FOREST AND MINERALS","question":"A company was prohibited from producing bags made from natural leopard skin. This is an attempt to conserve","images":[],"options":{"A":"Land","B":"water","C":"wildlife","D":"minerals"},"answer":"C","explanation":"The prohibition of a company from producing bags made from natural leopard skin is an attempt to conserve wildlife. This is because leopards are part of wildlife and their skin is a natural resource that needs to be conserved to prevent their extinction.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2020>40","subject":"Biology","year":"2020","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Which of the following susbtance is not a conversable natural resource ?","images":[],"options":{"A":"Mineral","B":"Air","C":"Soil","D":"Water"},"answer":"B","explanation":"Air is not a conservable natural resource because it is inexhaustible and cannot be depleted. Unlike minerals, soil, and water, air is constantly being replenished in the atmosphere and does not require conservation efforts to maintain its supply.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>41","subject":"Biology","year":"2020","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A child that can recieve blood donation from anybody belongs to the blood group","images":[],"options":{"A":"O","B":"A","C":"B","D":"AB"},"answer":"D","explanation":"A person with AB blood type is considered a universal recipient for blood transfusions because they can receive blood from donors of any blood type: A, B, AB, or O. This is because they have both A and B antigens on their red blood cells, so their body won't see any donated blood as foreign and attack it.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>42","subject":"Biology","year":"2020","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"Variation which exhibits a wide range from one extreme to other is","images":[],"options":{"A":"Phenotypic variation","B":"Discontinuous variation","C":"Continuous variation","D":"genotypic variation"},"answer":"C","explanation":"Continuous variation is the type of variation that exhibits a wide range from one extreme to the other. This type of variation is usually quantitative and results from the combined effect of many genes (polygenic), and often environmental factors also influence it. Examples include height, skin color, and body mass index (BMI).","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>43","subject":"Biology","year":"2020","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"Measurement of height and weight of students in a class show","images":[],"options":{"A":"Discontinuous variation","B":"Continuous variation","C":"Shortness is more prevalent.","D":"Fatness is less prevalent"},"answer":"B","explanation":"The measurement of height and weight of students in a class shows continuous variation. Continuous variation is a type of genetic variation where the individuals in a population vary in small ways from each other. This variation is usually due to the combined effect of multiple genes and environmental factors. Examples of continuous variation include height, weight, skin color, etc. In this case, the height and weight of students in a class will not be exactly the same for everyone, but will vary in a continuous manner.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>44","subject":"Biology","year":"2020","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"Which of the following statements about chromosomes is correct?","images":[],"options":{"A":"All the chromosomes of a species are the same in shape","B":"The number present in a species is constant","C":"They are neatly aranged in the cytoplasm","D":"They bear ribosomes on their outer memberanes"},"answer":"B","explanation":"The correct statement about chromosomes is that the number present in a species is constant. This is because each species has a specific number of chromosomes that is constant and unique to that species. For example, humans have 46 chromosomes, dogs have 78, and cats have 38. This number is constant and does not change, regardless of the individual's age, sex, or physical condition. The other options are incorrect because chromosomes can vary in shape, they are not neatly arranged in the cytoplasm, and they do not bear ribosomes on their outer membranes.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>45","subject":"Biology","year":"2020","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"Which of the following disease an be inherited ?","images":[],"options":{"A":"Pnuemonia","B":"AIDS","C":"Sickle cell anaemia","D":"Goitre"},"answer":"C","explanation":"Sickel cell anaemia can be inherited when the parent are carries of the sickl cell trait , there is high tendency for the offspring to be a sickel cell patient.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>46","subject":"Biology","year":"2020","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"The diagram below is an illustration of a cross between plants A and B of the same species.      If the F1 generation are plants with high yield and resistance, the genotype of th F1 generation plants would be","images":["data:image/jpeg;base64,"],"options":{"A":"YYRR","B":"YyRr","C":"yyRr","D":"yyrr"},"answer":"B","explanation":"Given the genotypes of the parent plants (A: YYrr and B: yyRR), the F1 generation, which are plants with high yield and resistance, would have the genotype:YyRr.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>47","subject":"Biology","year":"2020","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"The diagram below is an illustration of a cross between plants A and B of the same species.    The process that gave rise to the F1 generation is","images":["data:image/jpeg;base64,"],"options":{"A":"Self fertilization","B":"Cross fertilization","C":"Out-breeding","D":"test cross"},"answer":"D","explanation":"A test cross is a genetic technique used to determine the genotype of an individual organism with a dominant phenotype. It involves crossing the individual with a recessive homozygote (an individual with two recessive alleles) to produce offspring with a known genotype.    The purpose of a test cross is to:    1. Determine the genotype of an individual with a dominant phenotype   2. Identify whether an individual is homozygous dominant or heterozygous  3. Analyze the segregation of alleles and genes in the offspring.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>48","subject":"Biology","year":"2020","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Replication of DNA Molecules is catalysed by an enzyme called","images":[],"options":{"A":"Polymerase","B":"Ptyalin","C":"Pepsin","D":"amylase"},"answer":"A","explanation":"The replication of DNA molecules is catalysed by an enzyme called DNA polymerase. This enzyme adds nucleotides to the growing DNA chain and also has proofreading capabilities to ensure the accuracy of DNA replication. Ptyalin, Pepsin, and Amylase are all enzymes involved in the digestion of food, not in DNA replication.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>49","subject":"Biology","year":"2020","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Who proposed the theory of evolution by natural selection?","images":[],"options":{"A":"Darwin","B":"Lamarck","C":"Aristotle","D":"Linnaeus"},"answer":"A","explanation":"The theory of evolution by natural selection was proposed by Charles Darwin. This theory states that organisms that are better adapted to their environment are more likely to survive and reproduce, leading to the evolution of species over time.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2020>50","subject":"Biology","year":"2020","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following statement best explains the reason why termites swarm at night?","images":[],"options":{"A":"Light is not necessary for swarming","B":"They avoid day-flying birds","C":"Light destroys their wings","D":"they can only see in the dark."},"answer":"B","explanation":"Termites swarm at night to avoid predators such as day-flying birds. This is a survival strategy that allows them to reproduce and spread their colonies without being eaten.","marks":"1","difficulty":"2"}];